async function fillTextbox(el, value) {
    if (!value)
        return false;
    try {
        const label = extractLabel(el).toLowerCase();
        let finalValue = value;
        if (label.includes('month') || label.includes(' mm')) {
            // Extract month from "YYYY-MM-DD" if present
            if (value.match(/^\d{4}-\d{2}-\d{2}$/)) {
                const parts = value.split('-');
                if (parts.length === 3) {
                    finalValue = parts[1]; // "05"
                }
            }
            const monthMap = {
                'january': '01', 'february': '02', 'march': '03', 'april': '04',
                'may': '05', 'june': '06', 'july': '07', 'august': '08',
                'september': '09', 'october': '10', 'november': '11', 'december': '12',
                'jan': '01', 'feb': '02', 'mar': '03', 'apr': '04',
                'jun': '06', 'jul': '07', 'aug': '08', 'sep': '09', 'oct': '10', 'nov': '11', 'dec': '12'
            };
            if (monthMap[finalValue.toLowerCase()])
                finalValue = monthMap[finalValue.toLowerCase()];
        }
        else if (label.includes('year') || label.includes('yyyy')) {
            // Extract year from "YYYY-MM-DD" if present
            if (value.match(/^\d{4}-\d{2}-\d{2}$/)) {
                finalValue = value.split('-')[0];
            }
        }
        el.click();
        await sleep(150);
        el.focus();
        await sleep(100);
        try {
            // Updated to handle TypeScript any casting for internal prototype hacks
            let proto = Object.getPrototypeOf(el);
            let setter;
            while (proto && !setter) {
                const desc = Object.getOwnPropertyDescriptor(proto, 'value');
                if (desc && desc.set)
                    setter = desc.set;
                proto = Object.getPrototypeOf(proto);
            }
            if (setter)
                setter.call(el, finalValue);
            else if ('value' in el)
                el.value = finalValue;
            else {
                el.innerText = finalValue;
                el.textContent = finalValue;
            }
        }
        catch (e) {
            if ('value' in el)
                el.value = finalValue;
            else
                el.innerText = finalValue;
        }
        triggerInputEvent(el);
        await sleep(100);
        el.click();
        await sleep(100);
        triggerInputEvent(el);
        await sleep(50);
        el.blur();
        await sleep(50);
        console.log(`${LOG_PREFIX} ✅ Filled textbox: "${extractLabel(el)}" = "${finalValue}"`);
        return true;
    }
    catch (err) {
        console.error(`${LOG_PREFIX} ❌ Failed to fill textbox:`, err);
        return false;
    }
}
